// sounds.js — Ludo game audio data (base64 encoded)
// Host this file alongside index.html on GitHub Pages
// All sounds are decoded and loaded by index.html via SFX module

  const _DICE_B64 = ``;

  const _STEP_B64 = ``;

  const _CAPTURE_B64 = ``;

  const _STAR_B64 = ``;

  const _DONE_B64 = ``;

  const _GAMESTART_B64 = ``;

  const _lose_B64 = ``;

  const _win_B64 = ``;

SFX.registerExtra('dice',      _DICE_B64);
SFX.registerExtra('step',      _STEP_B64);
SFX.registerExtra('capture',   _CAPTURE_B64);
SFX.registerExtra('star',      _STAR_B64);
SFX.registerExtra('done',      _DONE_B64);
SFX.registerExtra('gamestart', _GAMESTART_B64);
SFX.registerExtra('win',       _win_B64);
SFX.registerExtra('lose',      _lose_B64);
